SELECT  
      STOCK_ID_SEQ.NEXTVAL AS stockId
    , 'C-' || TO_CHAR(SYSDATE, 'YYYYMMDD') || '-' || TO_CHAR(STOCK_ID_SEQ.NEXTVAL, 'FM0000000') AS contNo
FROM DUAL


INSERT INTO warehouse_stock (
      stock_id
    , unique_no
    , item_name
    , qty
    , gross_weight
    , warehouse_id
    , position_area
    , mem_id
    , rep_name
    , cont_no
    , damaged_yn
    , damaged_comment
) VALUES (
      #{stockId}
    , #{uniqueNo}
    , #{itemName}
    , #{qty}
    , #{grossWeight}
    , #{warehouseId}
    , #{positionArea}
    , #{memId}
    , #{repName}
    , #{contNo}
    , #{damagedYn}
    , #{damagedComment}
)

mapper.update:
UPDATE warehouse_stock
SET 
	  warehouse_id = #{warehouseId}
	, position_area = #{positionArea}
WHERE stock_id = #{stockId}

UPDATE warehouse_stock
SET 
	  del_yn = #{delYn}
	, out_date = SYSDATE
WHERE stock_id = #{stockId}
